const source = $json;
const p = source.pipeline || {};
const allowed = new Set(['OFFLINE', 'VALIDATE', 'DRY_RUN', 'LIVE']);
const requested = p.execution_mode;
const executionMode = typeof requested === 'string' && allowed.has(requested) ? requested : 'OFFLINE';
return [{json:{
  ...source,
  pipeline: {
    ...p,
    execution_mode: executionMode,
    dry_run: p.dry_run === false ? false : true,
    founder_write_approved: p.founder_write_approved === true,
    credentials_configured: p.credentials_configured === true
  }
}}];

const mode = $json.pipeline?.execution_mode === 'VALIDATE' ? 'VALIDATE' : 'OFFLINE';
return [{json:{
  document_id: $json.id || null,
  status: mode === 'VALIDATE' ? 'validate_local_only' : 'offline_local_only',
  execution_mode: mode,
  network_performed: false,
  write_performed: false,
  local_validation_required: true,
  validation_scope: ['manifest', 'registry', 'schema', 'workflows', 'secrets', 'execution_mode'],
  validation_command: 'python3 scripts/validate_manifest.py'
}}];

const doc = $json;
const p = doc.pipeline || {};
if (p.execution_mode !== 'DRY_RUN' && p.execution_mode !== 'LIVE') {
  throw new Error('Network access blocked by ExecutionMode.');
}
const headers = {
  Accept: 'application/vnd.github+json',
  'X-GitHub-Api-Version':'2022-11-28',
  Authorization:`Bearer ${$env.GITHUB_TOKEN}`
};
async function fetchFile(path) {
  const url = `https://api.github.com/repos/${p.github_owner}/${p.github_repo}/contents/${path}?ref=${p.branch}`;
  try {
    const r = await this.helpers.httpRequest({method:'GET',url,headers,json:true});
    return Buffer.from((r.content||'').replace(/\n/g,''),'base64').toString('utf8');
  } catch (e) {
    return '';
  }
}
const dependencies = {};
for (const dep of (doc.dependencies || [])) {
  // Dependency path lookup is intentionally delegated to a repository index.
  dependencies[dep] = await fetchFile(`generated/by-id/${dep}.md`);
}
const projectBible = await fetchFile('PROJECT_BIBLE.md');
const governance = await fetchFile('AGENTS.md');
return [{json:{...doc, context:{project_bible:projectBible, governance, dependencies}}}];

const d=$json;
const prompt = `You are the canonical enterprise-document generator for Damavand Steel.

DOCUMENT
ID: ${d.id}
Title: ${d.title}
Domain: ${d.domain}
Target path: ${d.path}
Minimum words: ${d.minimum_words}
Required sections: ${JSON.stringify(d.required_sections)}

NON-NEGOTIABLE RULES
1. Preserve Founder decisions and repository governance.
2. Do not invent unresolved business facts. Put them in open_questions.
3. Produce a complete detailed document, not an outline or summary.
4. Every business rule must be explicit, testable, and uniquely identifiable where possible.
5. Explain entities, fields, relationships, workflows, validations, exceptions, failure states, security, SEO, AI, and WordPress implications when relevant.
6. Do not use TODO/TBD in the document body.
7. Return valid JSON only.

CONTEXT — PROJECT BIBLE
${d.context.project_bible}

CONTEXT — GOVERNANCE
${d.context.governance}

CONTEXT — DEPENDENCIES
${JSON.stringify(d.context.dependencies)}

Return:
{
 "document_id":"${d.id}",
 "title":"${d.title}",
 "status":"draft",
 "version":"0.1.0",
 "markdown":"FULL MARKDOWN DOCUMENT",
 "dependencies_used":[],
 "entities_referenced":[],
 "rules_referenced":[],
 "open_questions":[],
 "acceptance_criteria":[]
}`;
return [{json:{...d,prompt}}];

const source = $('Build Generation Prompt').first().json;
let text = '';
if ($json.output_text) text = $json.output_text;
if (!text && Array.isArray($json.output)) {
  for (const out of $json.output) for (const c of (out.content||[])) if (c.text) text += c.text;
}
if (!text) throw new Error('OpenAI response contained no output text.');
let parsed;
try { parsed = JSON.parse(text); }
catch(e) {
  const m=text.match(/\{[\s\S]*\}/);
  if(!m) throw new Error('Model output is not valid JSON.');
  parsed=JSON.parse(m[0]);
}
return [{json:{...source, generated:parsed}}];

const d=$json, g=d.generated||{}, md=String(g.markdown||'');
const words=md.trim().split(/\s+/).filter(Boolean).length;
const headings=(md.match(/^##\s+/gm)||[]).length;
const missing=(d.required_sections||[]).filter(s=>{
  const norm=s.replace(/_/g,' ').toLowerCase();
  return !md.toLowerCase().includes('## '+norm);
});
const forbidden=/\b(TODO|TBD|PLACEHOLDER)\b/i.test(md);
const errors=[];
if(g.document_id!==d.id) errors.push('document_id mismatch');
if(words<Number(d.minimum_words||0)) errors.push(`word_count ${words} below ${d.minimum_words}`);
if(headings<8) errors.push(`too few H2 sections: ${headings}`);
if(missing.length) errors.push(`missing sections: ${missing.join(', ')}`);
if(forbidden) errors.push('forbidden placeholder token found');
return [{json:{...d, validation:{passed:errors.length===0,errors,word_count:words,heading_count:headings,missing_sections:missing}, markdown:md}}];

const d=$json;
const p=d.pipeline || {};
const allowed = new Set(['OFFLINE', 'VALIDATE', 'DRY_RUN', 'LIVE']);
const mode = typeof p.execution_mode === 'string' && allowed.has(p.execution_mode) ? p.execution_mode : 'OFFLINE';
const effectiveDryRun=p.dry_run !== false;
const founderApproved=p.founder_write_approved === true;
const credentialsConfigured=p.credentials_configured === true;
const workflowActive=$workflow.active === true;
let status='write_gate_blocked';
if(mode === 'DRY_RUN') status='dry_run_blocked_write';
else if(mode !== 'LIVE') status='execution_mode_blocked_write';
else if(effectiveDryRun) status='dry_run_blocked_write';
else if(!founderApproved) status='founder_approval_blocked_write';
else if(!credentialsConfigured) status='credentials_blocked_write';
else if(!workflowActive) status='inactive_workflow_blocked_write';
return [{json:{
  document_id:d.id,
  status,
  write_performed:false,
  execution_mode:mode,
  dry_run:effectiveDryRun,
  founder_write_approved:founderApproved,
  credentials_configured:credentialsConfigured,
  workflow_active:workflowActive,
  validation_status:'passed',
  path:d.path
}}];

const d=$json;
return [{json:{
  document_id:d.id,
  status:'validation_failed',
  validation_status:'failed',
  repair_required:true,
  errors:d.validation.errors,
  note:'Route this output to WF-03 Repair Loop after configuration.'
}}];

const d=$('Structural Validator').first().json;
return [{json:{
  document_id:d.id,
  status:'review_required',
  validation_status:'passed',
  write_performed:true,
  execution_mode:'LIVE',
  path:d.path,
  word_count:d.validation.word_count,
  github_commit:$json.commit?.sha || $json.content?.sha || null
}}];
